import{_ as e,o as l,c as o,ae as r}from"./chunks/framework.BzQXgbNp.js";const p=JSON.parse('{"title":"🧭 遊戲內傳送與地標指南","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Teleport-Commands.md","filePath":"Mc-Teleport-Commands.md"}'),a={name:"Mc-Teleport-Commands.md"};function d(s,t,n,i,g,c){return l(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="🧭-遊戲內傳送與地標指南" tabindex="-1">🧭 遊戲內傳送與地標指南 <a class="header-anchor" href="#🧭-遊戲內傳送與地標指南" aria-label="Permalink to &quot;🧭 遊戲內傳送與地標指南&quot;">​</a></h1><p>為了讓玩家在廣闊的世界中自由穿梭，Craft-Core 伺服器提供了完整的 <strong>傳送請求 (TPA)</strong>、<strong>個人家園與扣費規則 (Homes)</strong> 以及 <strong>公共地標與設施審核系統 (Warps &amp; Audit)</strong>。所有傳送指令皆已支援<strong>智慧型 Tab 自動補全與選擇器下拉選單</strong>。</p><hr><h2 id="👥-1-玩家間傳送指令-teleport-requests-tpa" tabindex="-1">👥 1. 玩家間傳送指令 (Teleport Requests / TPA) <a class="header-anchor" href="#👥-1-玩家間傳送指令-teleport-requests-tpa" aria-label="Permalink to &quot;👥 1. 玩家間傳送指令 (Teleport Requests / TPA)&quot;">​</a></h2><p>若想與其他線上玩家互傳，可以使用以下指令（已內建線上玩家選單自動補全）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">說明</th><th style="text-align:left;">參數說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>/tpa &lt;玩家名稱&gt;</code></strong></td><td style="text-align:left;">向指定線上玩家發送傳送請求，希望傳送到對方身邊</td><td style="text-align:left;">支援 Tab 自動選擇線上玩家</td></tr><tr><td style="text-align:left;"><strong><code>/tpahere &lt;玩家名稱&gt;</code></strong></td><td style="text-align:left;">向指定線上玩家發送傳送請求，希望對方傳送到您身邊</td><td style="text-align:left;">支援 Tab 自動選擇線上玩家</td></tr><tr><td style="text-align:left;"><strong><code>/tpaccept &lt;玩家名稱&gt;</code></strong></td><td style="text-align:left;">接受來自該玩家發送給您的傳送請求</td><td style="text-align:left;">可直接點擊聊天欄按鈕或 Tab 補全</td></tr><tr><td style="text-align:left;"><strong><code>/tpdeny &lt;玩家名稱&gt;</code></strong></td><td style="text-align:left;">拒絕來自該玩家發送給您的傳送請求</td><td style="text-align:left;">可直接點擊聊天欄按鈕或 Tab 補全</td></tr><tr><td style="text-align:left;"><strong><code>/tpa cancel</code></strong></td><td style="text-align:left;">取消您當前已發送給其他玩家的傳送請求</td><td style="text-align:left;">取消後可重新發送</td></tr></tbody></table><hr><h2 id="🏠-2-個人家園傳送與扣費規則-player-homes" tabindex="-1">🏠 2. 個人家園傳送與扣費規則 (Player Homes) <a class="header-anchor" href="#🏠-2-個人家園傳送與扣費規則-player-homes" aria-label="Permalink to &quot;🏠 2. 個人家園傳送與扣費規則 (Player Homes)&quot;">​</a></h2><p>玩家可以在任何安全的角落建立個人專屬的家園傳送點。</p><h3 id="📜-指令清單" tabindex="-1">📜 指令清單： <a class="header-anchor" href="#📜-指令清單" aria-label="Permalink to &quot;📜 指令清單：&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">說明</th><th style="text-align:left;">備註</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>/sethome &lt;家名稱&gt;</code></strong></td><td style="text-align:left;">在您當前站立的位置設定名為 <code>&lt;家名稱&gt;</code> 的家</td><td style="text-align:left;">若未輸入名稱預設為 <code>home</code></td></tr><tr><td style="text-align:left;"><strong><code>/home &lt;家名稱&gt;</code></strong></td><td style="text-align:left;">瞬間傳送至名為 <code>&lt;家名稱&gt;</code> 的家</td><td style="text-align:left;">支援下拉選單列出您已建立的家</td></tr><tr><td style="text-align:left;"><strong><code>/delhome &lt;家名稱&gt;</code></strong></td><td style="text-align:left;">刪除您已設定的名為 <code>&lt;家名稱&gt;</code> 的家</td><td style="text-align:left;">支援選單自動補全</td></tr><tr><td style="text-align:left;"><strong><code>/home list</code></strong></td><td style="text-align:left;">列出您目前擁有的所有家名稱與座標</td><td style="text-align:left;">也可在網頁儀表板管理</td></tr></tbody></table><h3 id="💰-家園數量限制與收費金額規則" tabindex="-1">💰 家園數量限制與收費金額規則： <a class="header-anchor" href="#💰-家園數量限制與收費金額規則" aria-label="Permalink to &quot;💰 家園數量限制與收費金額規則：&quot;">​</a></h3><ol><li><strong>免費額度</strong>：每位玩家預設享有 <strong>2 個免費家園 (Homes)</strong> 額度。建立前 2 個家園完全免收任何費用。</li><li><strong>多餘家園收費 ($300/個)</strong>： <ul><li>當您已有 2 個或以上的家園時，每當您<strong>新建一個全新名稱的家園（第 3 個至第 15 個家園）</strong>，系統將自動從您的個人遊戲帳戶中扣除 <strong>$300 遊戲幣</strong>手續費。</li><li>若您的金幣餘額不足 $300，系統將拒絕建立並提示：<code>§c[Craft-Core] 金額不足！建立超過 2 個的家需要 $300 遊戲幣。</code></li></ul></li><li><strong>同名家園覆蓋更新 (免費)</strong>： <ul><li>若您是對已存在的同名家園進行重設（例如對已有的 <code>home1</code> 再次執行 <code>/sethome home1</code> 更新座標），此操作為<strong>完全免費</strong>，不收取任何費用。</li></ul></li><li><strong>上限限制</strong>：每位玩家最多可擁有的家園上限為 <strong>15 個</strong>。</li></ol><hr><h2 id="🏁-3-公共地標傳送指令-warps" tabindex="-1">🏁 3. 公共地標傳送指令 (Warps) <a class="header-anchor" href="#🏁-3-公共地標傳送指令-warps" aria-label="Permalink to &quot;🏁 3. 公共地標傳送指令 (Warps)&quot;">​</a></h2><p>公共地標為官方或玩家審核通過的公共區域傳送點：</p><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">說明</th><th style="text-align:left;">權限/備註</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>/warp &lt;地標名稱&gt;</code></strong></td><td style="text-align:left;">瞬間傳送至指定公共地標（如 <code>/warp spawn</code>）</td><td style="text-align:left;">所有人皆可使用，支援選單自動補全</td></tr><tr><td style="text-align:left;"><strong><code>/warp list</code></strong></td><td style="text-align:left;">列出伺服器中所有的公共地標與座標</td><td style="text-align:left;">所有人皆可使用</td></tr><tr><td style="text-align:left;"><strong><code>/setwarp &lt;地標名稱&gt;</code></strong></td><td style="text-align:left;">在當前位置建立新的公共地標</td><td style="text-align:left;">僅限 OP 管理員使用</td></tr><tr><td style="text-align:left;"><strong><code>/delwarp &lt;地標名稱&gt;</code></strong></td><td style="text-align:left;">刪除指定的地標</td><td style="text-align:left;">僅限 OP 管理員使用</td></tr></tbody></table><hr><h2 id="📍-4-公共設施與-warp-投稿審核系統" tabindex="-1">📍 4. 公共設施與 Warp 投稿審核系統 <a class="header-anchor" href="#📍-4-公共設施與-warp-投稿審核系統" aria-label="Permalink to &quot;📍 4. 公共設施與 Warp 投稿審核系統&quot;">​</a></h2><p>為了鼓勵玩家建造刷鐵機、公共農場、紅石設施與玩家小鎮，伺服器提供<strong>公共設施審核與 Warp 自動建立流程</strong>：</p><h3 id="🤖-discord-頻道審核-1524354515661492344" tabindex="-1">🤖 Discord 頻道審核 (<code>1524354515661492344</code>) <a class="header-anchor" href="#🤖-discord-頻道審核-1524354515661492344" aria-label="Permalink to &quot;🤖 Discord 頻道審核 (`1524354515661492344`)&quot;">​</a></h3><ol><li>前往 Discord <strong><code>1524354515661492344</code></strong> 頻道。</li><li>檢視現有公共傳送點列表 Embed，並點擊 <strong><code>📝 提交公共設施 / Warp 審核</code></strong> 按鈕。</li><li>在彈出的 Modal 表單中填寫： <ul><li><strong>設施名稱</strong>（如 <code>刷鐵機</code> / <code>公共農場</code>）</li><li><strong>設施功能說明</strong>（如 <code>免費提供鐵錠與紅石物資</code>）</li><li><strong>設施座標 (X Y Z)</strong>（如 <code>150 64 -200</code>）</li><li><strong>所在世界</strong>（預設為 <code>overworld</code> 主世界）</li></ul></li><li>提交後自動送交管理員頻道審核，管理員點擊 <code>✅ 同意通過</code> 時，系統會<strong>自動在遊戲內設立 <code>/warp &lt;名稱&gt;</code> 並同步更新 Discord 與網頁清單</strong>！</li></ol><h3 id="🖥️-web-dashboard-傳送與審核管理-teleports" tabindex="-1">🖥️ Web Dashboard 傳送與審核管理 (<code>/teleports</code>) <a class="header-anchor" href="#🖥️-web-dashboard-傳送與審核管理-teleports" aria-label="Permalink to &quot;🖥️ Web Dashboard 傳送與審核管理 (`/teleports`)&quot;">​</a></h3><ul><li>前往網頁儀表板的 <strong>「傳送點管理」</strong> 分頁： <ul><li><strong>我的家園</strong>：即時查看與遠端刪除個人 Home 點。</li><li><strong>公共地標</strong>：檢視所有公共 Warp 點與座標。</li><li><strong>設施審核</strong>：線上提交設施審核，管理員可於此直接進行 <code>✅ 核准</code> 與 <code>❌ 駁回</code>。</li></ul></li></ul><hr><h2 id="💸-5-安全金幣轉帳-pay-與其他傳送機制" tabindex="-1">💸 5. 安全金幣轉帳 (<code>/pay</code>) 與其他傳送機制 <a class="header-anchor" href="#💸-5-安全金幣轉帳-pay-與其他傳送機制" aria-label="Permalink to &quot;💸 5. 安全金幣轉帳 (`/pay`) 與其他傳送機制&quot;">​</a></h2><ul><li><strong><code>/pay &lt;玩家&gt; &lt;金額&gt;</code></strong>： <ul><li>發送轉帳請求後，聊天欄會顯示黃色 <strong><code>[點擊確認發送 $X 給 Y]</code></strong> 按鈕，需在 10 秒內二次確認才扣款，防止打錯名字或金額。</li><li>設有 3 秒轉帳冷卻時間，確保資金安全。</li></ul></li><li><strong><code>/back</code></strong>：傳送回上一次的傳送位置或死亡地點。</li><li><strong><code>/rtp</code></strong>：隨機傳送至地圖 Safe 地點（冷卻時間 60 秒）。</li><li><strong>商店傳送</strong>：一般玩家可透過 <code>/shop</code> 點選商品頁中間的 <strong><code>[傳送到商店]</code></strong> 安全抵達玩家店面。</li></ul>',27)])])}const f=e(a,[["render",d]]);export{p as __pageData,f as default};
